// Filter to active competitors only and normalize field names
const active = items.filter(i => {
  const v = (i.json['Active'] || i.json['active'] || '').toString().toLowerCase();
  return v === 'yes' || v === 'true' || v === '1';
});

if (active.length === 0) {
  throw new NodeOperationError(this.getNode(), 'No active competitors found in the sheet. Set Active=Yes for at least one row.');
}

return active.map(i => ({
  json: {
    name: i.json['Competitor Name'] || i.json['name'] || 'Unknown',
    url: (i.json['URL'] || i.json['url'] || '').trim(),
    lastContent: i.json['Last Content'] || '',
    lastHash: i.json['Content Hash'] || '',
    lastChecked: i.json['Last Checked'] || '',
    lastChanged: i.json['Last Changed'] || ''
  }
})).filter(i => i.json.url);

// Extract visible text from HTML and detect content changes
function extractText(html) {
  if (!html || typeof html !== 'string') return '';
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 3000);
}

function simpleHash(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) {
    h = Math.imul(31, h) + str.charCodeAt(i) | 0;
  }
  return Math.abs(h).toString(16);
}

const competitor = $('Filter Active Competitors').item.json;
const rawHtml = $input.item.json.data || $input.item.json.body || '';

const newText = extractText(rawHtml);
const newHash = simpleHash(newText);
const oldHash = competitor.lastHash || '';
const isFirstRun = !oldHash;
const changed = !isFirstRun && newHash !== oldHash;

return [{
  json: {
    name: competitor.name,
    url: competitor.url,
    newText,
    newHash,
    oldContent: competitor.lastContent || '',
    changed,
    isFirstRun,
    lastChanged: competitor.lastChanged || ''
  }
}];

// Parse AI output into structured fields
const output = $input.item.json.output || '';
const headlineMatch = output.match(/HEADLINE:\s*(.+)/);
const changesMatch = output.match(/CHANGES:\n([\s\S]+?)(?=IMPACT:|$)/);
const impactMatch = output.match(/IMPACT:\s*(.+)/);

const headline = headlineMatch ? headlineMatch[1].trim() : 'Website content changed';
const changes = changesMatch ? changesMatch[1].trim() : '';
const impact = impactMatch ? impactMatch[1].trim() : '';

return [{
  json: {
    ...$input.item.json,
    headline,
    changes,
    impact,
    aiSummary: `${headline}\n\n${changes}\n\nImpact: ${impact}`.trim()
  }
}];

