// Build daily digest from all processed competitors
const changed = items.filter(i => i.json.changed);
const unchanged = items.filter(i => !i.json.changed);

if (changed.length === 0) {
  return [{
    json: {
      hasChanges: false,
      digestText: `✅ *Daily Competitor Check — ${new Date().toLocaleDateString('en-US', {weekday:'long', month:'short', day:'numeric'})}*\n\nNo changes detected across ${items.length} competitor(s) today.`
    }
  }];
}

const changesSummary = changed.map(i => {
  const d = i.json;
  return `*${d.name}* — ${d.headline || 'Content changed'}\n${d.url}`;
}).join('\n\n');

return [{
  json: {
    hasChanges: true,
    changedCount: changed.length,
    totalCount: items.length,
    digestText: `📊 *Daily Competitor Digest — ${new Date().toLocaleDateString('en-US', {weekday:'long', month:'short', day:'numeric'})}*\n\n*${changed.length} change(s)* detected out of ${items.length} competitors monitored:\n\n${changesSummary}\n\n_See Slack alerts above for full AI analysis._`
  }
}];
